#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-16

# =============================================================================
# Directive density check — Opus 4.7 literal-instruction audit
# =============================================================================
# Opus 4.7 takes instructions more literally than 4.6. Skills with many
# MUST/CRITICAL/NEVER markers risk turning aspirational guidance into
# hard rules the model enforces inflexibly.
#
# This test reports directive counts per 100 lines for every SKILL.md and
# flags skills above a threshold. It runs in ADVISORY mode by default —
# exit 0 with a report. Set DIRECTIVE_DENSITY_ENFORCE=1 to fail the run
# when skills exceed the threshold (after baseline is curated).
#
# Threshold rationale: 4 directives per 100 lines is roughly one per
# section heading in a typical 400-line SKILL.md — more than that usually
# indicates boilerplate repetition rather than genuine hard constraints.
#
# Pattern-library skills (architecture-patterns, database-patterns,
# python-backend, etc.) legitimately use NEVER to teach anti-patterns.
# They can opt out by including this HTML comment in the SKILL.md:
#     <!-- directive-density: intentional (teaches anti-patterns) -->
# =============================================================================

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../../.." && pwd)"
SKILLS_DIR="$REPO_ROOT/src/skills"
BASELINE_FILE="$SCRIPT_DIR/.directive-density-baseline.json"

RED='\033[0;31m'; GREEN='\033[0;32m'; YELLOW='\033[1;33m'
BLUE='\033[0;34m'; BOLD='\033[1m'; NC='\033[0m'

THRESHOLD_PER_100_LINES="${DIRECTIVE_DENSITY_THRESHOLD:-4}"
ENFORCE="${DIRECTIVE_DENSITY_ENFORCE:-0}"
OPTOUT_MARKER="directive-density: intentional"

echo -e "${BLUE}${BOLD}Directive-density check (MUST/CRITICAL/NEVER per 100 lines)${NC}"
echo -e "  Threshold: ${THRESHOLD_PER_100_LINES} directives / 100 lines"
echo -e "  Mode:      $([[ "$ENFORCE" == "1" ]] && echo "ENFORCE (fails on breach)" || echo "advisory (report only)")"
echo ""

offenders=()
intentional=()
report_rows=()

while IFS= read -r -d '' skill_md; do
    skill_name="$(basename "$(dirname "$skill_md")")"
    total_lines="$(wc -l < "$skill_md" | tr -d ' ')"
    [[ "$total_lines" -eq 0 ]] && continue

    # Count as whole-word matches so we don't hit "MUSTARD" etc.
    directive_count="$(grep -cE '\b(MUST|CRITICAL|NEVER)\b' "$skill_md" || true)"
    per_100="$(awk -v c="$directive_count" -v t="$total_lines" 'BEGIN { printf "%.2f", (c * 100) / t }')"

    report_rows+=("$(printf '%-40s %6s lines %5s directives %8s / 100' "$skill_name" "$total_lines" "$directive_count" "$per_100")")

    # Floating-point comparison without bc
    if awk -v p="$per_100" -v t="$THRESHOLD_PER_100_LINES" 'BEGIN { exit (p > t) ? 0 : 1 }'; then
        if grep -q "$OPTOUT_MARKER" "$skill_md"; then
            intentional+=("$(printf '%s (%s / 100 lines)' "$skill_name" "$per_100")")
        else
            offenders+=("$(printf '%s (%s / 100 lines)' "$skill_name" "$per_100")")
        fi
    fi
done < <(find "$SKILLS_DIR" -name SKILL.md -print0 | sort -z)

# Ranked report — top 15 by density
echo -e "${BOLD}Top skills by directive density:${NC}"
printf '%s\n' "${report_rows[@]}" | sort -k7 -nr | head -15 | while IFS= read -r row; do
    echo -e "  $row"
done
echo ""

if [[ ${#intentional[@]} -gt 0 ]]; then
    echo -e "${BLUE}${#intentional[@]} skill(s) above threshold but marked intentional (pattern libraries):${NC}"
    printf '  - %s\n' "${intentional[@]}"
    echo ""
fi

if [[ ${#offenders[@]} -eq 0 ]]; then
    echo -e "${GREEN}✓ All non-opted-out skills under threshold (${THRESHOLD_PER_100_LINES}/100)${NC}"
    exit 0
fi

echo -e "${YELLOW}⚠ ${#offenders[@]} skill(s) exceed the ${THRESHOLD_PER_100_LINES}/100 threshold without opt-out:${NC}"
printf '  - %s\n' "${offenders[@]}"
echo ""
echo -e "${BLUE}  To mark a pattern-library skill as intentional, add this comment to SKILL.md:${NC}"
echo -e "  <!-- directive-density: intentional (teaches anti-patterns) -->"
echo ""

# Write baseline snapshot on every run (informational; not a golden)
if [[ ! -f "$BASELINE_FILE" ]] || [[ "${DIRECTIVE_DENSITY_REGEN_BASELINE:-0}" == "1" ]]; then
    {
        echo "{"
        echo "  \"generated_at\": \"$(date -u +%Y-%m-%dT%H:%M:%SZ)\","
        echo "  \"threshold_per_100_lines\": $THRESHOLD_PER_100_LINES,"
        echo "  \"offender_count\": ${#offenders[@]},"
        echo "  \"offenders\": ["
        for i in "${!offenders[@]}"; do
            comma=","; [[ $i -eq $((${#offenders[@]} - 1)) ]] && comma=""
            echo "    \"${offenders[$i]}\"$comma"
        done
        echo "  ]"
        echo "}"
    } > "$BASELINE_FILE"
    echo -e "${BLUE}Baseline written to $BASELINE_FILE${NC}"
fi

if [[ "$ENFORCE" == "1" ]]; then
    echo -e "${RED}✗ Enforcement enabled — failing due to directive-density breach.${NC}"
    exit 1
fi

echo -e "${YELLOW}(Advisory mode — not failing. Set DIRECTIVE_DENSITY_ENFORCE=1 to fail.)${NC}"
exit 0
